const SOPS = {
  'SOP-01': {
    titre: 'Vérification connectivité Lightsoft',
    resume: 'Confirmer l\'accès à la supervision Lightsoft et la cohérence des alarmes.',
    etapes: [
      { num: 1, titre: 'Ping gateway OOB', desc: 'Depuis la station NOC, ping 10.0.0.1. Timeout = problème réseau OOB.', sp_ref: '' },
      { num: 2, titre: 'Ouvrir Lightsoft', desc: 'URL: http://lightsoft.internal — login admin.', sp_ref: 'OPSCNY-01-01' },
      { num: 3, titre: 'Vérifier alarmes actives', desc: 'Menu Supervision > Alarmes. Noter criticité et heure.', sp_ref: '' },
    ]
  },
  'SOP-02': {
