      { num: 3, titre: 'Reset GCC', desc: 'Commande CLI Ribbon : restart gcc-port. Attendre 30s.', sp_ref: 'OPSCNY-01-02' },
      { num: 4, titre: 'Vérifier OSPF hello', desc: 'Lightsoft : alarme OSPF doit disparaître sous 90s.', sp_ref: '' },
    ]
  },
  'SOP-03': {
    titre: 'Escalade Ribbon TAC',
    resume: 'Ouvrir un SR Ribbon Support si l\'incident n\'est pas auto-cleared après SOP-01/02.',
    etapes: [
      { num: 1, titre: 'Préparer les informations', desc: 'Numéro de châssis, version logicielle, alarmes actives, logs GCC.', sp_ref: '' },
      { num: 2, titre: 'Créer le SR', desc: 'Portal : support.ribboncommunications.com > Create Service Request.', sp_ref: '' },
      { num: 3, titre: 'Envoyer les logs', desc: 'Lightsoft > Export > System Logs (24h). Joindre au SR.', sp_ref: '' },
    ]
  },
  'SOP-04': {
    titre: 'Diagnostic optique OSNR / SPAN LOSS',
    resume: 'Mesurer et interpréter les niveaux optiques sur la chaîne OTN.',
    etapes: [
      { num: 1, titre: 'Ouvrir Lightsoft > Supervision', desc: 'Menu Supervision > Vue topologie > sélectionner le lien concerné.', sp_ref: 'OPSCNY-01-03' },
      { num: 2, titre: 'Relever OSNR', desc: 'Colonne OSNR doit être > 12 dB sur chaque canal. Valeur < 10 dB = critique.', sp_ref: '' },
      { num: 3, titre: 'Mesurer SPAN LOSS', desc: 'Span Loss = différence Tx/Rx en dBm. Seuil normal < 20 dB.', sp_ref: '' },
      { num: 4, titre: 'Inspecter connecteurs optiques', desc: 'Si SPAN LOSS élevé : nettoyer les connecteurs SC/PC avec kit IBC.', sp_ref: '' },
    ]
  },
  'SOP-05': {
    titre: 'Diagnostic FEC / BER',
    resume: 'Analyser les compteurs FEC et le taux d\'erreur bit sur les ports OTN.',
    etapes: [
      { num: 1, titre: 'Lightsoft > PM Counters', desc: 'Sélectionner port > onglet Performance Monitoring.', sp_ref: 'OPSCNY-02-13' },
      { num: 2, titre: 'Lire FEC corrected/uncorrected', desc: 'FEC corrected en hausse = dégradation optique. Uncorrected > 0 = critique.', sp_ref: '' },
      { num: 3, titre: 'Vérifier BER pre/post FEC', desc: 'Pre-FEC BER > 1e-3 = problème signal. Post-FEC BER > 0 = urgence.', sp_ref: '' },
    ]
  },
  'SOP-06': {
    titre: 'Remplacement carte service (LB/HB/VHB)',
    resume: 'Procédure de remplacement d\'une carte en défaut sur châssis Ribbon Apollo.',
    etapes: [
      { num: 1, titre: 'Confirmer la panne en DB', desc: 'Lightsoft : carte en état FAILED ou MISMATCH. SR Ribbon ouvert (SOP-03).', sp_ref: '' },
      { num: 2, titre: 'Prévoir la carte de remplacement', desc: 'Vérifier le stock spare. Référence carte : étiquette châssis.', sp_ref: '' },
      { num: 3, titre: 'Informer les clients affectés', desc: 'Identifier les ports UNI/NNI sur la carte. Notifier avant intervention.', sp_ref: '' },
      { num: 4, titre: 'Extraire la carte défaillante', desc: 'Déverrouiller la carte, tirer avec précaution. ESD obligatoire.', sp_ref: '' },
      { num: 5, titre: 'Insérer la carte de remplacement', desc: 'Insérer jusqu\'au clic. Lightsoft : état IN-SERVICE sous 2 min.', sp_ref: '' },
      { num: 6, titre: 'Valider la restauration', desc: 'SOP-13 (Viavi) obligatoire pour confirmation service.', sp_ref: 'OPSCNY-02-14' },
    ]
  },
  'SOP-07': {
    titre: 'Remplacement SFP / transceiver',
    resume: 'Changer un SFP défectueux sur un port OTN ou OOB.',
    etapes: [
      { num: 1, titre: 'Identifier le port en LOS', desc: 'Lightsoft : alarme LOS sur port spécifique. Relever numéro de slot.', sp_ref: '' },
      { num: 2, titre: 'Mesurer puissance optique', desc: 'Utiliser un power meter sur le connecteur d\'entrée. Puissance nulle = SFP mort.', sp_ref: '' },
      { num: 3, titre: 'Extraire le SFP', desc: 'Déverrouiller le levier du SFP. ESD obligatoire.', sp_ref: '' },
      { num: 4, titre: 'Insérer le SFP de remplacement', desc: 'Même référence (longueur d\'onde, portée). Insérer jusqu\'au clic.', sp_ref: '' },
      { num: 5, titre: 'Vérifier la remontée optique', desc: 'Lightsoft : LOS doit disparaître sous 60s. OSNR dans les normes.', sp_ref: '' },
    ]
  },
  'SOP-08': {
    titre: 'Vérification OOB Cogent / EuNetwork',
    resume: 'Diagnostiquer la perte d\'accès OOB via les liens Cogent et EuNetwork.',
    etapes: [
      { num: 1, titre: 'Vérifier état physique OOB', desc: 'Contrôler les LEDs du switch OOB Telehouse. Lien UP = vert.', sp_ref: '' },
      { num: 2, titre: 'Ping opérateur OOB', desc: 'Ping gateway Cogent (10.x.x.1) ET EuNetwork (10.x.x.2).', sp_ref: '' },
      { num: 3, titre: 'Vérifier routing OOB', desc: 'Traceroute vers Sese-AI. Comparer routes Cogent vs EuNetwork.', sp_ref: '' },
      { num: 4, titre: 'Escalade opérateur si Down', desc: 'Cogent NOC : +33 1 XX XX XX. EuNetwork NOC : ticket portail.', sp_ref: '' },
    ]
  },
  'SOP-09': {
    titre: 'Diagnostic firewall Lugos',
    resume: 'Vérifier et restaurer les règles de filtrage Lugos sur l\'accès management.',
    etapes: [
      { num: 1, titre: 'Accéder à Lugos via console', desc: 'Accès console physique ou IPMI si OOB indisponible.', sp_ref: '' },
      { num: 2, titre: 'Vérifier les règles actives', desc: 'lugos show rules | grep management. Confirmer que les IPs NOC sont autorisées.', sp_ref: '' },
      { num: 3, titre: 'Réactiver la règle si désactivée', desc: 'lugos enable rule <id>. Tester l\'accès depuis le poste NOC.', sp_ref: '' },
    ]
  },
  'SOP-10': {
    titre: 'Procédure bascule OLP',
    resume: 'Gérer un protection switch déclenché sur un lien OTN (OLP = Optical Line Protection).',
    etapes: [
      { num: 1, titre: 'Identifier le switch OLP', desc: 'Lightsoft > Protection > état Working/Protect. Colonne Switch Reason.', sp_ref: '' },
      { num: 2, titre: 'Vérifier la fibre Working', desc: 'Mesurer OSNR/puissance sur le chemin Working. Comparer au chemin Protect actif.', sp_ref: '' },
      { num: 3, titre: 'Décider du revert', desc: 'Si chemin Working restauré : Lightsoft > Protection > Manual Revert.', sp_ref: '' },
      { num: 4, titre: 'Confirmer la stabilité', desc: 'Observer 5 minutes. Pas de re-switch = stable. SOP-04 si dégradation persiste.', sp_ref: '' },
    ]
  },
  'SOP-11': {
    titre: 'Analyse PM Counters Lightsoft',
    resume: 'Analyser les compteurs de performance pour identifier une dégradation progressive.',
    etapes: [
      { num: 1, titre: 'Lightsoft > PM Counters', desc: 'Sélectionner l\'interface > onglet Performance Monitoring > période 24h.', sp_ref: 'OPSCNY-02-13' },
      { num: 2, titre: 'Exporter les données', desc: 'Bouton Export CSV. Analyser ES (Errored Seconds) et SES (Severely Errored Seconds).', sp_ref: '' },
      { num: 3, titre: 'Comparer aux seuils ITU-T G.826', desc: 'ES < 0.4% sur 24h. SES < 0.05% sur 24h.', sp_ref: '' },
      { num: 4, titre: 'Identifier la tendance', desc: 'Si dégradation progressive → SOP-04 ou SOP-07. Ponctuelle → SOP-10.', sp_ref: '' },
    ]
  },
  'SOP-12': {
    titre: 'PM Counters détaillés (OPSCNY-02-13)',
    resume: 'Procédure complète d\'analyse des compteurs PM sur châssis Ribbon, référence OPSCNY-02-13.',
    etapes: [
      { num: 1, titre: 'Accéder à l\'interface PM', desc: 'Lightsoft > Equipment > sélectionner châssis > Performance Monitoring.', sp_ref: 'OPSCNY-02-13' },
      { num: 2, titre: 'Sélectionner la période', desc: '15 min pour diagnostic temps réel. 24h pour tendance. 30 jours pour bilan mensuel.', sp_ref: '' },
      { num: 3, titre: 'Analyser les compteurs OTU', desc: 'OTU2: FEC-CW-COR, FEC-CW-UNCOR, BBE, ES, SES, UAS. Chaque compteur > 0 = anomalie.', sp_ref: '' },
      { num: 4, titre: 'Analyser les compteurs ODU', desc: 'ODU2: BBE-PM, ES-PM, SES-PM, UAS-PM. Comparer aux seuils ITU-T G.826.', sp_ref: '' },
      { num: 5, titre: 'Exporter le rapport', desc: 'Export PDF depuis Lightsoft. Joindre au rapport d\'intervention.', sp_ref: 'OPSCNY-02-13' },
