  'SOP-13': {
    titre: 'Validation Viavi OTU2 post-restauration (OPSCNY-02-14)',
    resume: 'Test de validation RFC 2544 / OTU2 après remplacement physique. Preuve de restauration service.',
    etapes: [
      { num: 1, titre: 'Connecter le Viavi MTS-5800', desc: 'Port OTU2 du MTS-5800 sur le port UNI/NNI à valider. Mode: OTU2 10.7G.', sp_ref: 'OPSCNY-02-14' },
      { num: 2, titre: 'Configurer le test RFC 2544', desc: 'Throughput, Latency, Frame Loss, Back-to-Back. Taille trames: 64, 128, 256, 512, 1024, 1518 bytes.', sp_ref: '' },
      { num: 3, titre: 'Lancer le test', desc: 'Durée minimale: 60s par taille de trame. Noter les résultats.', sp_ref: '' },
