    ]
  }
};

const q = $input.first().json.query || {};
const sop_id = q.sop_id;
const sops_list = (q.sops_list || '').split(',').filter(Boolean);
const idx = parseInt(q.idx ?? '0', 10);

if (!sop_id) {
  return [{ json: { error: 'missing sop_id', statusCode: 400 } }];
}

const sop = SOPS[sop_id];
if (!sop) {
  return [{ json: { error: `SOP ${sop_id} inconnue`, statusCode: 404 } }];
}

const next_idx = idx + 1;
const is_last = next_idx >= sops_list.length;
const next_sop = is_last ? null : sops_list[next_idx];

return [{ json: { ...sop, sop_id, next_sop, is_last, current_idx: idx } }];
